#include <bits/stdc++.h>
using namespace std;
int n,deep[102],fa[102][8],sum[102],mxd=1,mxk=1;
vector<int> g[102];
void set_thing(){
    queue<int> q;
    q.push(1),deep[1]=1,sum[1]++;
    while(q.size()){
        int f=q.front(),len=g[f].size();
        q.pop();
        for(int i=0;i<len;i++)
            if(!deep[g[f][i]]){
                int v=g[f][i];
                deep[v]=deep[f]+1,q.push(v),sum[deep[v]]++;
                mxd=max(mxd,deep[v]),mxk=max(mxk,sum[deep[v]]);
                fa[v][0]=f;
                for(int j=1;j<8;j++)
                    fa[v][j]=fa[fa[v][j-1]][j-1];
            }
    }
}
int LCA(int x,int y){
    if(deep[x]<deep[y])
        swap(x,y);
    for(int i=7;i>=0;i--)
        if(deep[fa[x][i]]>=deep[y])
            x=fa[x][i];
    if(x==y)
        return x;
    for(int i=7;i>=0;i--)
        if(fa[x][i] && fa[y][i] && fa[x][i]!=fa[y][i])
            x=fa[x][i],y=fa[y][i];
    return fa[x][0];
}
int main(){
    scanf("%d",&n);
    for(int i=1;i<n;i++){
        int u,v;
        scanf("%d%d",&u,&v);
        g[u].push_back(v);
        g[v].push_back(u);
    }
    int x,y;
    scanf("%d%d",&x,&y);
    set_thing();
    printf("%d\n%d\n",mxd,mxk);
    int cf=LCA(x,y);
    printf("%d",(deep[x]-deep[cf])*2+deep[y]-deep[cf]);
    return 0;
}
